package com.hiliving.content.news;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;import java.time.Instant;import java.util.*;public interface NewsRepository extends JpaRepository<NewsEntity,Long>{@Query("select n from NewsEntity n where n.published=true and (n.publishedAt is null or n.publishedAt<=:now) order by coalesce(n.publishedAt,n.createdAt) desc,n.id desc")List<NewsEntity> findPublic(@Param("now")Instant now);@Query("select n from NewsEntity n where n.slug=:slug and n.published=true and (n.publishedAt is null or n.publishedAt<=:now)")Optional<NewsEntity> findPublicBySlug(@Param("slug")String slug,@Param("now")Instant now);boolean existsBySlugAndIdNot(String slug,Long id);long countByPublishedTrue();}
